-- ── 1. Create gps_staging table ─────────────────────────────────

CREATE TABLE IF NOT EXISTS public.gps_staging (
  id               UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  lat              DECIMAL(10,8) NOT NULL,
  lng              DECIMAL(11,8) NOT NULL,
  shop_hint        TEXT,
  ward_hint        TEXT,
  municipality_hint TEXT,
  raw_context      TEXT,
  match_score      DECIMAL(4,2),
  auto_matched     BOOLEAN DEFAULT FALSE,
  assigned_to      UUID REFERENCES public.assessments(id),
  assigned_at      TIMESTAMPTZ,
  created_at       TIMESTAMPTZ DEFAULT now()
);

-- ── 2. Enable RLS ────────────────────────────────────────────────

ALTER TABLE public.gps_staging ENABLE ROW LEVEL SECURITY;

-- ── 3. RLS policies ──────────────────────────────────────────────

-- Authenticated users can read staging pins
DROP POLICY IF EXISTS "authenticated_select_gps_staging" ON public.gps_staging;
CREATE POLICY "authenticated_select_gps_staging"
  ON public.gps_staging
  FOR SELECT
  USING (auth.role() = 'authenticated');

-- Coordinators (role_tier <= 2) can update staging pins
-- Using permissive policy for now
DROP POLICY IF EXISTS "coordinators_update_gps_staging" ON public.gps_staging;
CREATE POLICY "coordinators_update_gps_staging"
  ON public.gps_staging
  FOR UPDATE
  USING (true)
  WITH CHECK (true);

-- ── 4. Seed 138 GPS rows from gps_review.csv ────────────────────

ON CONFLICT DO NOTHING;

-- ── Done ─────────────────────────────────────────────────────────
